const rows = $input.all().map(item => item.json);

const total = rows.length;

const waiting = rows.filter(row =>
  String(row["Tracker Status"] || "").toLowerCase().includes("waiting")
);

const notConfirmed = rows.filter(row =>
  String(row["Human Payment Status"] || "").toLowerCase() === "not confirmed"
);

const highRisk = rows.filter(row =>
  ["high", "urgent"].includes(String(row["Risk Level"] || "").toLowerCase())
);

const failedPayments = rows.filter(row =>
  String(row["Transaction Type"] || "").toLowerCase().includes("failed")
);

const supplierInvoices = rows.filter(row =>
  String(row["Transaction Type"] || "").toLowerCase().includes("invoice")
);

return [{
  json: {
    success: true,
    message: "Transaction tracker search completed.",
    total_rows_found: total,
    waiting_for_bfc_team_count: waiting.length,
    not_human_confirmed_count: notConfirmed.length,
    high_or_urgent_risk_count: highRisk.length,
    failed_payment_count: failedPayments.length,
    supplier_invoice_count: supplierInvoices.length,
    rows: rows.map(row => ({
      date_scanned: row["Date Scanned"] || "",
      transaction_type: row["Transaction Type"] || "",
      direction: row["Direction"] || "",
      supplier_or_customer: row["Supplier / Customer"] || "",
      amount: row["Amount"] || "",
      due_date: row["Due Date"] || "",
      invoice_or_reference: row["Invoice / Reference"] || "",
      source_system: row["Source System"] || "",
      evidence_summary: row["Evidence Summary"] || "",
      xero_match: row["Xero Match"] || "",
      attachment_status: row["Attachment Status"] || "",
      ai_payment_status: row["AI Payment Status"] || "",
      human_payment_status: row["Human Payment Status"] || "",
      risk_level: row["Risk Level"] || "",
      recommended_next_action: row["Recommended Next Action"] || "",
      tracker_status: row["Tracker Status"] || "",
      notes: row["Notes"] || "",
      source_id_or_link: row["Source ID / Link"] || "",
      created_by: row["Created By"] || ""
    }))
  }
}];
